$$I see a bird / Look at this photo / I watch TV.$$,
$j$[{"en": "I can see the mountains from here.", "pt": "Consigo ver as montanhas daqui."}, {"en": "Look at that painting.", "pt": "Olhe aquele quadro."}, {"en": "We watched a movie last night.", "pt": "Assistimos a um filme ontem."}]$j$::jsonb,
