$j$[{"en": "I want to open an account.", "pt": "Quero abrir uma conta."}, {"en": "She withdrew some money.", "pt": "Ela sacou dinheiro."}, {"en": "What's my balance?", "pt": "Qual é o meu saldo?"}]$j$::jsonb,
