('C2', 3039, $$Ênfase com 'do' (emphatic)$$, $$I do believe you$$, $$❗$$,
$$O 'do/does/did' auxiliar pode enfatizar uma afirmação: 'I do like it' (eu REALMENTE gosto). Usa-se com o verbo na forma base.$$,
$$Serve para reforçar ou contrariar uma dúvida: 'I did call you!' (eu liguei sim!).$$,
$j$[{"en": "I do appreciate your help.", "pt": "Eu realmente agradeço sua ajuda."}, {"en": "She does work hard.", "pt": "Ela trabalha muito mesmo."}, {"en": "We did enjoy the trip.", "pt": "Nós curtimos a viagem sim."}]$j$::jsonb,
$j$[{"q": "'Eu REALMENTE gosto' =", "ctx": "", "opts": ["I do like it", "I am like it", "I like do it", "I very like it"], "ans": 0, "exp": "do + base."}, {"q": "Depois de 'do' enfático, o verbo fica:", "ctx": "", "opts": ["na forma base", "no passado", "com -ing", "com to"], "ans": 0, "exp": "forma base."}, {"q": "'Ela trabalha muito MESMO' =", "ctx": "", "opts": ["She does work hard", "She works do hard", "She do works hard", "She is work hard"], "ans": 0, "exp": "does work."}, {"q": "'Eu liguei SIM!' =", "ctx": "", "opts": ["I did call you", "I called do you", "I do called you", "I did called you"], "ans": 0, "exp": "did call."}, {"q": "O 'do' enfático serve para:", "ctx": "", "opts": ["reforçar/contrariar dúvida", "fazer pergunta", "negar", "pedir"], "ans": 0, "exp": "ênfase."}, {"q": "Correto:", "ctx": "", "opts": ["Please do sit down.", "Please do sitting.", "Please do sat.", "Please do to sit."], "ans": 0, "exp": "do + base (sit)."}]$j$::jsonb),

('C2', 3040, $$Expressões latinas no inglês$$, $$per se, vice versa, e.g.$$, $$🏛️$$,
$$O inglês formal usa expressões latinas: per se (em si), vice versa (o contrário também), e.g. (por exemplo), i.e. (isto é), etc., versus, status quo, ad hoc.$$,
$$e.g. = por exemplo; i.e. = ou seja. Não confunda os dois.$$,
$j$[{"en": "The idea isn't bad per se.", "pt": "A ideia não é ruim em si."}, {"en": "Fruits, e.g. apples and pears.", "pt": "Frutas, por exemplo maçãs e peras."}, {"en": "He helps her and vice versa.", "pt": "Ele a ajuda e vice-versa."}]$j$::jsonb,
$j$[{"q": "'per se' =", "ctx": "", "opts": ["em si mesmo", "por favor", "perto", "depois"], "ans": 0, "exp": "em si."}, {"q": "'e.g.' =", "ctx": "", "opts": ["por exemplo", "isto é", "etc.", "ou seja"], "ans": 0, "exp": "por exemplo."}, {"q": "'i.e.' =", "ctx": "", "opts": ["isto é/ou seja", "por exemplo", "e assim por diante", "versus"], "ans": 0, "exp": "isto é."}, {"q": "'vice versa' =", "ctx": "", "opts": ["o contrário também", "de novo", "por acaso", "ao vivo"], "ans": 0, "exp": "o inverso."}, {"q": "'status quo' =", "ctx": "", "opts": ["situação atual", "status alto", "estatística", "parada"], "ans": 0, "exp": "situação atual."}, {"q": "'ad hoc' =", "ctx": "", "opts": ["feito para um fim específico", "antigo", "adicional só", "aleatório"], "ans": 0, "exp": "para um fim específico."}]$j$::jsonb);
